const items = $input.all();
const item = items[0];

const binaryKeys = Object.keys(item.binary || {});
const resumeKey = binaryKeys.find(k => 
  k.toLowerCase().includes('resume') || 
  k.toLowerCase().includes('file')
) || binaryKeys[0];

if (!resumeKey || !item.binary[resumeKey]) {
  throw new Error('No resume file found. Please upload a PDF file.');
}

return [{
  json: {
    ...item.json,
    resumeBinaryKey: resumeKey,
    jobDescription: item.json['Job Description'] || item.json.jobDescription || '',
    candidateName: item.json['Candidate Name'] || item.json.candidateName || 'Candidate',
    emailAddress: item.json['Email Address'] || item.json.emailAddress || ''
  },
  binary: item.binary
}];

const item = $input.first();
let resumeText = item.json.text || item.json.content || '';

if (!resumeText && Array.isArray(item.json)) {
  resumeText = item.json.map(p => p.text || '').join('\n');
}

if (!resumeText) {
  const textFields = Object.entries(item.json)
    .filter(([k, v]) => typeof v === 'string' && v.length > 50)
    .map(([k, v]) => v);
  resumeText = textFields.join('\n');
}

return [{
  json: {
    resumeText: resumeText.trim(),
    jobDescription: item.json.jobDescription || '',
    candidateName: item.json.candidateName || 'Candidate',
    emailAddress: item.json.emailAddress || ''
  }
}];

const item = $input.first();
let jdAnalysis = {};

try {
  const responseText = item.json.text || item.json.response || item.json.output || '';
  const cleaned = responseText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '');
  jdAnalysis = JSON.parse(cleaned);
} catch(e) {
  const text = item.json.text || item.json.response || '';
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try { jdAnalysis = JSON.parse(jsonMatch[0]); } catch(e2) {}
  }
}

return [{
  json: {
    resumeText: item.json.resumeText || '',
    jobDescription: item.json.jobDescription || '',
    candidateName: item.json.candidateName || 'Candidate',
    emailAddress: item.json.emailAddress || '',
    jdAnalysis: jdAnalysis
  }
}];

// Code node that generates HTML resume and ATS report
// See full workflow for complete implementation

return [{
  json: {
    html: '<html><body>Optimized Resume HTML</body></html>',
    reportHtml: '<html><body>ATS Report HTML</body></html>',
    candidateName: 'Candidate Name',
    atsscore: '75'
  }
}];
